import { NavLink } from 'react-router-dom';

function Header() {
  return (
    <header>
      <NavLink
        to="/"
        style={({ isActive }) => ({
          fontWeight: isActive ? 'bold' : 'normal'
        })}
      >
        Home
      </NavLink>
      <NavLink
        to="/about"
        className={({ isActive }) => isActive ? 'active-link' : ''}
      >
        About
      </NavLink>
    </header>
  );
}
